query:
-- Mettre vatRate=20 pour les items des commandes FR (id 2 et 3)
UPDATE order_items SET vatRate = '20.00' WHERE orderId IN (2, 3);
-- Mettre vatRate=0 pour les items de la commande ES (id 1)
UPDATE order_items SET vatRate = '0.00' WHERE orderId = 1;

-- Recalculer totalVAT et totalTTC des items pour CMD-TEST-001 et CMD-TEST-002
-- orderId=2 : Easy Relax totalHT=2090 (avec remise), mais on stocke avec remise en base
-- Note: on ne touche pas totalHT des items (c'est recalculé à la volée dans l'API)
-- On met juste vatRate à jour pour cohérence
SELECT oi.orderId, oi.name, oi.vatRate, oi.totalHT, oi.totalVAT, oi.totalTTC 
FROM order_items oi WHERE oi.orderId IN (1, 2, 3);

